1	const PROCESSING_FEE = 5;
2	const COMPONENT_BLOCK_SIZE = 3;
3	const COMPONENT_BLOCK_PREMIUM = 60;
4	const COMPONENT_TYPES = ["rune", "moonstone"];
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	type Item = { type: string; cursed?: boolean; enchantment?: number };
18	
19	const basePremiumFor = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
20	
21	const isHighlyEnchanted = (item: Item): boolean =>
22	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
23	
24	const surchargeRate = (item: Item): number =>
25	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
26	  (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
27	
28	const mainItemPremium = (item: Item): number => {
29	  const base = basePremiumFor(item);
30	  return base + base * surchargeRate(item);
31	};
32	
33	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
34	
35	const componentGroupPremium = (group: Item[]): number =>
36	  group.length === COMPONENT_BLOCK_SIZE
37	    ? COMPONENT_BLOCK_PREMIUM
38	    : group.reduce((sum, item) => sum + basePremiumFor(item), 0);
39	
40	const groupComponentsByType = (items: Item[]): Item[][] => {
41	  const groups: Record<string, Item[]> = {};
42	  for (const item of items) {
43	    (groups[item.type] ||= []).push(item);
44	  }
45	  return Object.values(groups);
46	};
47	
48	export function quote(_customer: { yearsWithMHPCO: number }, items: Item[]): number {
49	  const components = items.filter(isComponent);
50	  const mainItems = items.filter((item) => !isComponent(item));
51	  const mainTotal = mainItems.reduce((sum, item) => sum + mainItemPremium(item), 0);
52	  const componentTotal = groupComponentsByType(components).reduce(
53	    (sum, group) => sum + componentGroupPremium(group),
54	    0,
55	  );
56	  return mainTotal + componentTotal + PROCESSING_FEE;
57	}
